import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './AuthPage.css';

function SignupPage() {
  const navigate = useNavigate();
  const auth = useAuth?.() || {};
  const signup = auth?.signup || auth?.register || (async () => true);

  const [form, setForm] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    agreeTerms: true,
    agreeMarketing: false,
  });

  const [focusedField, setFocusedField] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');

  const emailValid = useMemo(() => /\S+@\S+\.\S+/.test(form.email), [form.email]);
  const nameValid = useMemo(() => form.name.trim().length >= 2, [form.name]);
  const passwordValid = useMemo(() => form.password.length >= 8, [form.password]);
  const confirmValid = useMemo(
    () => form.confirmPassword.length > 0 && form.password === form.confirmPassword,
    [form.password, form.confirmPassword]
  );

  const passwordStrength = useMemo(() => {
    let score = 0;
    if (form.password.length >= 8) score += 1;
    if (/[A-Z]/.test(form.password) || /[a-z]/.test(form.password)) score += 1;
    if (/\d/.test(form.password)) score += 1;
    if (/[^A-Za-z0-9]/.test(form.password)) score += 1;

    if (score <= 1) return { label: '약함', className: 'weak', width: '25%' };
    if (score === 2) return { label: '보통', className: 'medium', width: '55%' };
    if (score === 3) return { label: '좋음', className: 'good', width: '78%' };
    return { label: '매우 좋음', className: 'strong', width: '100%' };
  }, [form.password]);

  const canSubmit =
    nameValid &&
    emailValid &&
    passwordValid &&
    confirmValid &&
    form.agreeTerms &&
    !isSubmitting;

  const handleChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!canSubmit) return;

    setIsSubmitting(true);
    setError('');

    try {
      const result = await signup({
        name: form.name,
        email: form.email,
        password: form.password,
        agreeTerms: form.agreeTerms,
        agreeMarketing: form.agreeMarketing,
      });

      if (result === false) {
        throw new Error('회원가입에 실패했습니다.');
      }

      navigate('/dashboard');
    } catch (err) {
      setError(err?.message || '회원가입 중 오류가 발생했습니다. 다시 시도해주세요.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <section className="auth-page auth-signup-page">
      <div className="auth-aurora auth-aurora-1"></div>
      <div className="auth-aurora auth-aurora-2"></div>
      <div className="auth-aurora auth-aurora-3"></div>

      <div className="container auth-layout reverse">
        <div className="auth-brand-panel">
          <Link to="/" className="auth-brand-link">
            <div className="auth-brand-mark">
              <span className="auth-brand-ring"></span>
              <span className="auth-brand-dot"></span>
            </div>

            <div className="auth-brand-copy">
              <strong>메이티</strong>
              <span>AI Emotion Companion</span>
            </div>
          </Link>

          <div className="auth-brand-content">
            <div className="auth-page-badge">Get started</div>

            <h1 className="auth-brand-title">
              나만의 감정 동반자를
              <br />
              <span className="gradient-text">지금 시작해보세요</span>
            </h1>

            <p className="auth-brand-description">
              회원가입은 더 짧고 직관적으로, 첫인상은 더 세련되게 만들었습니다.
              메이티는 가입 순간부터 제품의 감도와 신뢰감을 전달합니다.
            </p>

            <div className="auth-preview-card">
              <div className="auth-preview-top">
                <span className="preview-mini-label">Setup Preview</span>
                <span className="preview-mini-chip">Personalized</span>
              </div>

              <div className="auth-preview-list">
                <div className="auth-preview-item">
                  <strong>1. AI 친구 선택</strong>
                  <p>하루 또는 루미 중 원하는 캐릭터 선택</p>
                </div>
                <div className="auth-preview-item">
                  <strong>2. 대화 톤 설정</strong>
                  <p>차분함 / 활기 / 공감 강도까지 세밀하게 조정</p>
                </div>
                <div className="auth-preview-item">
                  <strong>3. 감정 케어 시작</strong>
                  <p>일상 속에서 메이티가 먼저 다가오는 경험</p>
                </div>
              </div>
            </div>

            <div className="auth-floating-metrics">
              <div className="auth-metric-card">
                <span className="auth-metric-label">Onboarding</span>
                <strong>Simple</strong>
              </div>
              <div className="auth-metric-card">
                <span className="auth-metric-label">Interaction</span>
                <strong>Warm</strong>
              </div>
            </div>
          </div>
        </div>

        <div className="auth-form-panel">
          <div className="auth-form-shell glow-ring">
            <div className="auth-form-header">
              <div>
                <span className="auth-form-eyebrow">Create account</span>
                <h2>회원가입</h2>
                <p>메이티와 함께하는 첫 감정 케어 경험을 시작하세요.</p>
              </div>

              <div className="auth-form-status">
                <span className="auth-status-dot"></span>
                Smooth Onboarding
              </div>
            </div>

            <form className="auth-form" onSubmit={handleSubmit}>
              <div
                className={`auth-input-group ${
                  focusedField === 'name' ? 'focused' : ''
                } ${form.name ? 'filled' : ''}`}
              >
                <label htmlFor="signup-name">이름</label>
                <input
                  id="signup-name"
                  type="text"
                  placeholder="이름 또는 닉네임"
                  value={form.name}
                  onFocus={() => setFocusedField('name')}
                  onBlur={() => setFocusedField('')}
                  onChange={(e) => handleChange('name', e.target.value)}
                  autoComplete="name"
                />
                <span className={`auth-valid-chip ${nameValid ? 'valid' : ''}`}>
                  {form.name ? (nameValid ? '좋아요' : '2자 이상 입력') : '입력 대기'}
                </span>
              </div>

              <div
                className={`auth-input-group ${
                  focusedField === 'email' ? 'focused' : ''
                } ${form.email ? 'filled' : ''}`}
              >
                <label htmlFor="signup-email">이메일</label>
                <input
                  id="signup-email"
                  type="email"
                  placeholder="name@example.com"
                  value={form.email}
                  onFocus={() => setFocusedField('email')}
                  onBlur={() => setFocusedField('')}
                  onChange={(e) => handleChange('email', e.target.value)}
                  autoComplete="email"
                />
                <span className={`auth-valid-chip ${emailValid ? 'valid' : ''}`}>
                  {form.email ? (emailValid ? '유효한 이메일' : '이메일 형식 확인') : '입력 대기'}
                </span>
              </div>

              <div className="auth-double-grid">
                <div
                  className={`auth-input-group ${
                    focusedField === 'password' ? 'focused' : ''
                  } ${form.password ? 'filled' : ''}`}
                >
                  <label htmlFor="signup-password">비밀번호</label>
                  <div className="auth-password-wrap">
                    <input
                      id="signup-password"
                      type={showPassword ? 'text' : 'password'}
                      placeholder="8자 이상"
                      value={form.password}
                      onFocus={() => setFocusedField('password')}
                      onBlur={() => setFocusedField('')}
                      onChange={(e) => handleChange('password', e.target.value)}
                      autoComplete="new-password"
                    />
                    <button
                      type="button"
                      className="auth-toggle-btn"
                      onClick={() => setShowPassword((prev) => !prev)}
                    >
                      {showPassword ? '숨김' : '보기'}
                    </button>
                  </div>

                  <div className="auth-password-strength">
                    <div className="auth-strength-bar">
                      <span
                        className={`auth-strength-fill ${passwordStrength.className}`}
                        style={{ width: passwordStrength.width }}
                      ></span>
                    </div>
                    <span className={`auth-strength-text ${passwordStrength.className}`}>
                      {form.password ? passwordStrength.label : '비밀번호 강도'}
                    </span>
                  </div>
                </div>

                <div
                  className={`auth-input-group ${
                    focusedField === 'confirmPassword' ? 'focused' : ''
                  } ${form.confirmPassword ? 'filled' : ''}`}
                >
                  <label htmlFor="signup-confirm-password">비밀번호 확인</label>
                  <div className="auth-password-wrap">
                    <input
                      id="signup-confirm-password"
                      type={showConfirmPassword ? 'text' : 'password'}
                      placeholder="비밀번호 다시 입력"
                      value={form.confirmPassword}
                      onFocus={() => setFocusedField('confirmPassword')}
                      onBlur={() => setFocusedField('')}
                      onChange={(e) => handleChange('confirmPassword', e.target.value)}
                      autoComplete="new-password"
                    />
                    <button
                      type="button"
                      className="auth-toggle-btn"
                      onClick={() => setShowConfirmPassword((prev) => !prev)}
                    >
                      {showConfirmPassword ? '숨김' : '보기'}
                    </button>
                  </div>

                  <span className={`auth-valid-chip ${confirmValid ? 'valid' : ''}`}>
                    {form.confirmPassword
                      ? confirmValid
                        ? '비밀번호 일치'
                        : '비밀번호 불일치'
                      : '입력 대기'}
                  </span>
                </div>
              </div>

              <div className="auth-check-list">
                <label className="auth-check">
                  <input
                    type="checkbox"
                    checked={form.agreeTerms}
                    onChange={(e) => handleChange('agreeTerms', e.target.checked)}
                  />
                  <span>
                    <strong>(필수)</strong> 이용약관 및 개인정보 처리방침에 동의합니다.
                  </span>
                </label>

                <label className="auth-check">
                  <input
                    type="checkbox"
                    checked={form.agreeMarketing}
                    onChange={(e) => handleChange('agreeMarketing', e.target.checked)}
                  />
                  <span>(선택) 업데이트 및 혜택 알림 수신에 동의합니다.</span>
                </label>
              </div>

              {error && <div className="auth-error-box">{error}</div>}

              <button
                type="submit"
                className={`btn btn-primary auth-submit-btn ${
                  isSubmitting ? 'loading' : ''
                }`}
                disabled={!canSubmit}
              >
                {isSubmitting ? (
                  <>
                    <span className="auth-spinner"></span>
                    가입 중...
                  </>
                ) : (
                  '회원가입 완료'
                )}
              </button>

              <div className="auth-bottom-copy">
                이미 계정이 있으신가요? <Link to="/login">로그인</Link>
              </div>
            </form>

            <div className="auth-floating-pill top">Pastel Professional</div>
            <div className="auth-floating-pill bottom">Trust-centered Flow</div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default SignupPage;
